import{_ as e,o as i,c as a,a3 as r}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Pricing & Budget","description":"","frontmatter":{"title":"Pricing & Budget"},"headers":[],"relativePath":"en/advertisers/pricing.md","filePath":"en/advertisers/pricing.md"}'),s={name:"en/advertisers/pricing.md"};function n(l,t,o,d,c,g){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="pricing-model" tabindex="-1">Pricing Model <a class="header-anchor" href="#pricing-model" aria-label="Permalink to &quot;Pricing Model&quot;">​</a></h1><p>getinside is a self-service platform. Free access, transparent model, no commitment.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Item</th><th style="text-align:left;">Cost</th><th style="text-align:left;">Mandatory</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Platform Access</strong></td><td style="text-align:left;">Free</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>Platform Fee</strong></td><td style="text-align:left;">12% of invested media budget</td><td style="text-align:left;">✅ Yes</td></tr><tr><td style="text-align:left;"><strong>Creative Studio</strong></td><td style="text-align:left;">Flat fee 550€ HT per creation</td><td style="text-align:left;">Optional</td></tr><tr><td style="text-align:left;"><strong>Printing &amp; Logistics</strong></td><td style="text-align:left;">Sliding scale rates (all included)</td><td style="text-align:left;">Optional</td></tr><tr><td style="text-align:left;"><strong>Dedicated Account Manager</strong></td><td style="text-align:left;">Free from 5,000€ HT budget</td><td style="text-align:left;">Automatic</td></tr></tbody></table><hr><h2 id="platform-fee" tabindex="-1">Platform Fee <a class="header-anchor" href="#platform-fee" aria-label="Permalink to &quot;Platform Fee&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><div class="gi-price">12% <span class="gi-price-unit">of invested media budget</span></div><ul><li>✅ <strong>No subscription</strong> — Platform access is free.</li><li>✅ <strong>No minimum budget</strong> — Test with small amounts.</li><li>✅ <strong>Unlimited access</strong> to the inventory of +250 exclusive audiences.</li><li>✅ <strong>Single centered invoice</strong> — regardless of the number of audiences purchased.</li></ul></div><div class="info custom-block"><p class="custom-block-title">When is the invoice generated?</p><p>Billing is triggered as soon as you definitively validate the <strong>Purchase Order</strong> on the platform. No billing before your validation.</p></div><hr><h2 id="optional-services" tabindex="-1">Optional Services <a class="header-anchor" href="#optional-services" aria-label="Permalink to &quot;Optional Services&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎨 Creative Studio</strong><div class="gi-price">550€ <span class="gi-price-unit">HT / creation</span></div><p>Art direction, execution, and standardization of your materials — Print (A5/A6 flyer), Email or Social. The studio guarantees technical compliance before printing.</p></div><div class="gi-value-card"><strong>🖨️ Printing &amp; Logistics</strong><p>Sliding scale rates for grouped purchases. Unit cost decreases with volume. All included: printing (Made in France, Imprim&#39;Vert), finishing, and warehouse delivery.</p><p>→ <a href="./printing-services">Service details</a></p></div><div class="gi-value-card"><strong>♻️ Wallet — Reinvestment</strong><p>Are you also an e-retailer (Distributor)? Use the monetization revenue stored in your Wallet to fund your acquisition campaigns — instant transfer, no bank cash outflow.</p></div></div><hr><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Dedicated Account Manager — from 5,000€ HT</p><p>From <strong>5,000€ HT</strong> of invested media budget, you benefit for free from a dedicated Account Manager for:</p><ul><li>Targeting strategy (Lookalike, First Party Data)</li><li>Selection of the most relevant audiences</li><li>Optimization of your ongoing campaigns</li></ul></div><div class="info custom-block"><p class="custom-block-title">Media Agency Program</p><p>Do you manage multiple advertiser accounts? An agency program with dedicated conditions is available on request.</p><p>→ <a href="mailto:benoit@getinside.fr" target="_blank" rel="noreferrer">Contact the Sales team</a></p></div>',16)])])}const f=e(s,[["render",n]]);export{u as __pageData,f as default};
